// index.js — Google Cloud Function, Node.js 20
const { PubSub } = require("@google-cloud/pubsub");

const pubsub = new PubSub();
const WORKER_TOPIC = process.env.WORKER_TOPIC; // e.g. "agent-jobs"

/**
 * Entry point triggered by Pub/Sub push subscription.
 * Decodes the message, validates required fields, and re-publishes
 * to the worker topic with enriched metadata.
 *
 * @param {object} message  Cloud Functions Pub/Sub message object
 */
exports.agentEnqueue = async (message) => {
  // Pub/Sub delivers data as base64-encoded JSON
  const raw = Buffer.from(message.data, "base64").toString("utf-8");
  let payload;
  try {
    payload = JSON.parse(raw);
  } catch (e) {
    console.error("Invalid JSON payload", raw);
    return; // Acking (returning without throw) prevents retry
  }

  const { runId, prompt, callbackUrl } = payload;
  if (!runId || !prompt) {
    console.error("Missing required fields", { runId, prompt });
    return;
  }

  const topic = pubsub.topic(WORKER_TOPIC);
  await topic.publishMessage({
    json: { runId, prompt, callbackUrl, enqueuedAt: Date.now() },
    attributes: { runId, source: "webhook" },
  });

  console.log(JSON.stringify({ event: "enqueued", runId, promptLength: prompt.length }));
};

